#!/usr/bin/env python3
# Generated By: Claude Code (Claude Opus 4.6)
"""Claude Code status line.

Modes (auto-detected via CLAUDE_CODE_USE_VERTEX):
  Vertex/API (no limits): Model: <name> | Context: <pct>% | Session: $<amount>
  Max plan (quota):        Model: <name> | Context: <pct>% | 5h: <pct>% | 1w: <pct>%

Cost is session-scoped (total_cost_usd from Claude Code stdin).
Quota is account-wide (scans all JSONL transcripts in the time window).

Quota budgets are configurable via env vars:
  CLAUDE_5H_BUDGET     - weighted token budget for 5h window (default: 1000000)
  CLAUDE_WEEKLY_BUDGET - weighted token budget for weekly window (default: 10000000)
  Opus tokens count 5x vs Sonnet/Haiku.
"""

import json
import os
import sys
import time
from datetime import datetime
from pathlib import Path

CACHE_TTL_SECONDS = 60
OPUS_WEIGHT = 5


def get_model_weight(model_id):
    if "opus" in model_id.lower():
        return OPUS_WEIGHT
    return 1


def get_claude_project_dirs():
    home = Path.home()
    dirs = []
    for base in [home / ".claude", home / ".config" / "claude"]:
        projects = base / "projects"
        if projects.is_dir():
            for entry in projects.iterdir():
                if entry.is_dir():
                    dirs.append(entry)
    return dirs


def parse_jsonl_usage(filepath, since_ts):
    weighted = 0
    try:
        with open(filepath, "r", encoding="utf-8") as fh:
            for line in fh:
                line = line.strip()
                if not line:
                    continue
                try:
                    obj = json.loads(line)
                except json.JSONDecodeError:
                    continue
                ts_str = obj.get("timestamp")
                if not ts_str:
                    continue
                try:
                    dt = datetime.fromisoformat(ts_str.replace("Z", "+00:00"))
                    entry_ts = dt.timestamp()
                except (ValueError, OverflowError):
                    continue
                if entry_ts < since_ts:
                    continue
                msg = obj.get("message")
                if not msg:
                    continue
                usage = msg.get("usage")
                if not usage:
                    continue
                total = (
                    (usage.get("input_tokens") or 0)
                    + (usage.get("output_tokens") or 0)
                    + (usage.get("cache_creation_input_tokens") or 0)
                    + (usage.get("cache_read_input_tokens") or 0)
                )
                model = msg.get("model", "")
                weighted += total * get_model_weight(model)
    except OSError:
        pass
    return weighted


def get_quota_usage(hours, cache_dir, project_dirs):
    cache_file = cache_dir / f"quota_{hours}h.json"
    now = time.time()

    if cache_file.exists():
        try:
            with open(cache_file, "r") as fh:
                cached = json.load(fh)
            if now - cached.get("t", 0) < CACHE_TTL_SECONDS:
                return cached.get("v", 0)
        except (json.JSONDecodeError, OSError):
            pass

    since_ts = now - (hours * 3600)
    total_weighted = 0

    for project_dir in project_dirs:
        for pattern in ["*.jsonl", "*/subagents/agent-*.jsonl"]:
            for jsonl in project_dir.glob(pattern):
                try:
                    if jsonl.stat().st_mtime < since_ts:
                        continue
                except OSError:
                    continue
                total_weighted += parse_jsonl_usage(str(jsonl), since_ts)

    try:
        cache_dir.mkdir(parents=True, exist_ok=True)
        with open(cache_file, "w") as fh:
            json.dump({"v": total_weighted, "t": now}, fh)
    except OSError:
        pass

    return total_weighted


def main():
    try:
        data = json.load(sys.stdin)
    except (json.JSONDecodeError, EOFError):
        print("Claude Code")
        return

    model = data.get("model", {}).get("display_name", "Claude")
    parts = [f"Model: {model}"]

    ctx = data.get("context_window", {})
    used_pct = ctx.get("used_percentage")
    if used_pct is not None:
        parts.append(f"Context: {used_pct}%")

    is_vertex = bool(os.environ.get("CLAUDE_CODE_USE_VERTEX"))

    if is_vertex:
        cost = (data.get("cost") or {}).get("total_cost_usd")
        parts.append(f"Session: ${cost:.2f}" if cost is not None else "Session: $0.00")
    else:
        cache_dir = Path.home() / ".claude" / "statusline-cache"
        budget_5h = int(os.environ.get("CLAUDE_5H_BUDGET", "1000000"))
        budget_weekly = int(os.environ.get("CLAUDE_WEEKLY_BUDGET", "10000000"))

        project_dirs = get_claude_project_dirs()
        five_h = get_quota_usage(5, cache_dir, project_dirs)
        weekly = get_quota_usage(168, cache_dir, project_dirs)

        five_h_pct = min(100, round(five_h / budget_5h * 100)) if budget_5h else 0
        weekly_pct = (
            min(100, round(weekly / budget_weekly * 100)) if budget_weekly else 0
        )

        parts.append(f"5h: {five_h_pct}%")
        parts.append(f"1w: {weekly_pct}%")

    print(" | ".join(parts))


if __name__ == "__main__":
    main()
